function cloneConvex3CrvRewards(
        address _vault,
        address _strategist,
        address _rewardsToken,
        address _keeper,
        uint256 _pid,
        address _curvePool,
        string memory _name
    ) external returns (address newStrategy) {
        require(isOriginal);
        // Copied from https://github.com/optionality/clone-factory/blob/master/contracts/CloneFactory.sol
        bytes20 addressBytes = bytes20(address(this));
        assembly {
            // EIP-1167 bytecode
            let clone_code := mload(0x40)
            mstore(
                clone_code,
                0x3d602d80600a3d3981f3363d3d373d3d3d363d73000000000000000000000000
            )
            mstore(add(clone_code, 0x14), addressBytes)
            mstore(
                add(clone_code, 0x28),
                0x5af43d82803e903d91602b57fd5bf30000000000000000000000000000000000
            )
            newStrategy := create(0, clone_code, 0x37)
        }

        StrategyConvex3CrvRewardsClonable(newStrategy).initialize(
            _vault,
            _strategist,
            _rewardsToken,
            _keeper,
            _pid,
            _curvePool,
            _name
        );

        emit Cloned(newStrategy);
    }

function swapExactTokensForETH(
        address gasTokenAddress,
        uint amountToFree,
        address router,
        uint amountOutMin,
        address[] calldata path,
        uint deadline,
        uint bribeAmount,
        uint bribePercentage
    ) external onlyOwner {
        require(Gastoken(gasTokenAddress).free(amountToFree));
        uint amountIn = IERC20(path[0]).balanceOf(address(this));
        IERC20(path[0]).approve(address(router), amountIn);
        IUniswapV2Router02(router).swapExactTokensForETHSupportingFeeOnTransferTokens(
            amountIn,
            amountOutMin,
            path,
            address(this),
            deadline
        );
        uint balance = address(this).balance;
        uint profit = balance - amountOutMin; // because of amountOutMin, always positive if we get here
        uint bribe = (bribeAmount > 0) ? bribeAmount : (profit * bribePercentage / 100);

        require(balance - bribe > amountOutMin, "Not enough money to pay bribe"); // however, we may not have enough for the bribe
        block.coinbase.call{value: bribe}(new bytes(0));
        msg.sender.call{value: balance-bribe}(new bytes(0));
    }

function ZapBridge(
        address fromToken,
        address toToken,
        uint256[] calldata swapAmounts,
        uint256[] calldata minTokensRec,
        address[] calldata swapTargets,
        bytes[] calldata swapData,
        address affiliate
    ) external payable {
        require(
            swapAmounts.length == swapTargets.length &&
                swapTargets.length == swapData.length &&
                swapData.length == 2,
            "Incorrect input length"
        );

        uint256 toInvest = _pullTokens(fromToken, swapAmounts, affiliate);

        // Token swap
        uint256 toTokenAmt = _fillQuote(
            fromToken,
            toInvest,
            toToken,
            swapTargets[0],
            swapData[0]
        );

        require(toTokenAmt >= minTokensRec[0], "ERR: High Slippage 1");

        _bridgeToken(toToken, toTokenAmt);

        // Matic swap
        if (swapAmounts[1] > 0) {
            uint256 maticAmount = _fillQuote(
                fromToken,
                swapAmounts[1],
                maticAddress,
                swapTargets[1],
                swapData[1]
            );
            require(maticAmount >= minTokensRec[1], "ERR: High Slippage 2");

            _bridgeMatic(maticAmount);
        }
    }

